mapper.select:
WITH NMCP_FORM AS ( SELECT * FROM NMCP_FORM_DTL WHERE 1=1 AND CD_GROUP_ID1 IN ('FORMREQUIRED','FORMSELECT','FORMINFO') ) SELECT COUNT(*) FROM NMCP_FORM WHERE 1=1
AND CD_GROUP_ID1 = #{selectCdGroupId1}
AND CD_GROUP_ID2 = #{selectCdGroupId2}

WITH NMCP_FORM AS ( SELECT * FROM NMCP_FORM_DTL WHERE 1=1 AND CD_GROUP_ID1 IN ('FORMREQUIRED','FORMSELECT','FORMINFO') ) SELECT ROW_NUMBER() OVER(ORDER BY CD_GROUP_ID2 ,DOC_VER) AS R_NUM , CD_GROUP_ID1 , CD_GROUP_ID2 , DOC_VER , DOC_CONTENT , USE_YN , CRET_ID , CRET_DT , AMD_ID , AMD_DT , (SELECT DTL_CD_NM FROM NMCP_CD_DTL WHERE CD_GROUP_ID = CD_GROUP_ID1 AND DTL_CD = CD_GROUP_ID2) AS DTL_CD_NM FROM NMCP_FORM WHERE 1=1
AND CD_GROUP_ID1 = #{selectCdGroupId1}
AND CD_GROUP_ID2 = #{selectCdGroupId2}
ORDER BY CD_GROUP_ID2 ,DOC_VER

SELECT CD_GROUP_ID1 , CD_GROUP_ID2 , DOC_VER , USE_YN , CRET_ID , CRET_DT , AMD_ID , AMD_DT , CRET_DATE , DTL_CD_NM , EVENT_START_DT , EVENT_END_DT , DOC_CONTENT FROM ( SELECT CD_GROUP_ID1 , CD_GROUP_ID2 , DOC_VER , USE_YN , CRET_ID , CRET_DT , AMD_ID , AMD_DT , TO_CHAR(CRET_DT,'YYYY.MM.DD') AS CRET_DATE , (SELECT DTL_CD_NM FROM NMCP_CD_DTL WHERE CD_GROUP_ID = CD_GROUP_ID1 AND DTL_CD = CD_GROUP_ID2 AND ROWNUM = 1 ) AS DTL_CD_NM , CASE WHEN CURRENT_TIMESTAMP BETWEEN TO_TIMESTAMP(TO_CHAR(EVENT_START_DT, 'YYYYMMDD') || NVL(START_HOUR, '00'), 'YYYYMMDDHH24') AND TO_TIMESTAMP(TO_CHAR(EVENT_END_DT, 'YYYYMMDD') || NVL(END_HOUR, '23'), 'YYYYMMDDHH24') THEN TO_CHAR(EVENT_START_DT, 'YYYY.MM.DD') ELSE TO_CHAR(EVENT_START_DT_SEC, 'YYYY.MM.DD') END AS EVENT_START_DT , CASE WHEN CURRENT_TIMESTAMP BETWEEN TO_TIMESTAMP(TO_CHAR(EVENT_START_DT, 'YYYYMMDD') || NVL(START_HOUR, '00'), 'YYYYMMDDHH24') AND TO_TIMESTAMP(TO_CHAR(EVENT_END_DT, 'YYYYMMDD') || NVL(END_HOUR, '23'), 'YYYYMMDDHH24') THEN TO_CHAR(EVENT_END_DT, 'YYYY.MM.DD') ELSE TO_CHAR(EVENT_END_DT_SEC, 'YYYY.MM.DD') END AS EVENT_END_DT ,CASE WHEN CURRENT_TIMESTAMP BETWEEN TO_TIMESTAMP(TO_CHAR(EVENT_START_DT, 'YYYYMMDD') || NVL(START_HOUR, '00'), 'YYYYMMDDHH24') AND TO_TIMESTAMP(TO_CHAR(EVENT_END_DT, 'YYYYMMDD') || NVL(END_HOUR, '23'), 'YYYYMMDDHH24') THEN DOC_CONTENT ELSE DOC_CONTENT_SEC END AS DOC_CONTENT FROM NMCP_FORM_DTL WHERE CD_GROUP_ID1 = #{cdGroupId1} AND CD_GROUP_ID2 = #{cdGroupId2}
AND DOC_VER = #{docVer}
AND DOC_TYPE = #{docType}
AND EXPNSN_STR_VAL = #{expnsnStrVal}
ORDER BY DOC_VER DESC ) WHERE ROWNUM =1

SELECT CD_GROUP_ID1 , CD_GROUP_ID2 , DOC_VER , USE_YN , CRET_ID , CRET_DT , AMD_ID , AMD_DT , CRET_DATE , DTL_CD_NM , EVENT_START_DT , EVENT_END_DT , DOC_CONTENT FROM ( SELECT CD_GROUP_ID1 , CD_GROUP_ID2 , DOC_VER , USE_YN , CRET_ID , CRET_DT , AMD_ID , AMD_DT , TO_CHAR(CRET_DT,'YYYY.MM.DD') AS CRET_DATE , (SELECT DTL_CD_NM FROM NMCP_CD_DTL WHERE CD_GROUP_ID = CD_GROUP_ID1 AND DTL_CD = CD_GROUP_ID2 AND ROWNUM = 1 ) AS DTL_CD_NM , CASE WHEN #{adminEventDate} BETWEEN TO_TIMESTAMP(TO_CHAR(EVENT_START_DT, 'YYYYMMDD') || NVL(START_HOUR, '00'), 'YYYYMMDDHH24') AND TO_TIMESTAMP(TO_CHAR(EVENT_END_DT, 'YYYYMMDD') || NVL(END_HOUR, '23'), 'YYYYMMDDHH24') THEN TO_CHAR(EVENT_START_DT, 'YYYY.MM.DD') ELSE TO_CHAR(EVENT_START_DT_SEC, 'YYYY.MM.DD') END AS EVENT_START_DT , CASE WHEN #{adminEventDate} BETWEEN TO_TIMESTAMP(TO_CHAR(EVENT_START_DT, 'YYYYMMDD') || NVL(START_HOUR, '00'), 'YYYYMMDDHH24') AND TO_TIMESTAMP(TO_CHAR(EVENT_END_DT, 'YYYYMMDD') || NVL(END_HOUR, '23'), 'YYYYMMDDHH24') THEN TO_CHAR(EVENT_END_DT, 'YYYY.MM.DD') ELSE TO_CHAR(EVENT_END_DT_SEC, 'YYYY.MM.DD') END AS EVENT_END_DT ,CASE WHEN #{adminEventDate} BETWEEN TO_TIMESTAMP(TO_CHAR(EVENT_START_DT, 'YYYYMMDD') || NVL(START_HOUR, '00'), 'YYYYMMDDHH24') AND TO_TIMESTAMP(TO_CHAR(EVENT_END_DT, 'YYYYMMDD') || NVL(END_HOUR, '23'), 'YYYYMMDDHH24') THEN DOC_CONTENT ELSE DOC_CONTENT_SEC END AS DOC_CONTENT FROM NMCP_FORM_DTL WHERE CD_GROUP_ID1 = #{cdGroupId1} AND CD_GROUP_ID2 = #{cdGroupId2}
AND DOC_VER = #{docVer}
AND DOC_TYPE = #{docType}
AND EXPNSN_STR_VAL = #{expnsnStrVal}
ORDER BY DOC_VER DESC ) WHERE ROWNUM =1

SELECT
    NVL(MAX(DOC_VER)+1,1) AS DOC_VER
FROM NMCP_FORM_DTL
WHERE  CD_GROUP_ID1 = #{cdGroupId1}
AND    CD_GROUP_ID2 = #{cdGroupId2}

SELECT /*FormDtlMapper.getFormList 약관 정보 */ T1.CD_GROUP_ID1 , T1.CD_GROUP_ID2 , T1.DOC_VER , T1.DOC_CONTENT , T1.USE_YN , T1.CRET_ID , T1.CRET_DT , T1.AMD_ID , T1.AMD_DT , T2.DTL_CD_NM AS FORM_NM FROM NMCP_FORM_DTL T1 ,NMCP_CD_DTL T2 WHERE T1.USE_YN = 'Y' AND T1.CD_GROUP_ID1 =T2.CD_GROUP_ID AND T1.CD_GROUP_ID2 =T2.DTL_CD
AND T1.CD_GROUP_ID1 = #{cdGroupId1}
AND T1.CD_GROUP_ID2 = #{cdGroupId2}
AND T1.DOC_TYPE = '01' ORDER BY T1.CD_GROUP_ID2 , T1.DOC_VER

WITH NMCP_FORM_ETC AS ( SELECT * FROM NMCP_FORM_DTL WHERE 1=1 AND CD_GROUP_ID1 IN ('FormNotice','FormEtcCla') ) SELECT COUNT(*) FROM NMCP_FORM_ETC WHERE 1=1
AND CD_GROUP_ID1 = #{selectCdGroupId1}
AND CD_GROUP_ID2 = #{selectCdGroupId2}

WITH NMCP_FORM_ETC AS ( SELECT * FROM NMCP_FORM_DTL WHERE 1=1 AND CD_GROUP_ID1 IN ('FormNotice','FormEtcCla') ) SELECT ROW_NUMBER() OVER(ORDER BY CD_GROUP_ID2 ,DOC_VER) AS R_NUM , CD_GROUP_ID1 , CD_GROUP_ID2 , DOC_VER , DOC_CONTENT , USE_YN , CRET_ID , CRET_DT , AMD_ID , AMD_DT , (SELECT DTL_CD_NM FROM NMCP_CD_DTL WHERE CD_GROUP_ID = CD_GROUP_ID1 AND DTL_CD = CD_GROUP_ID2) AS DTL_CD_NM FROM NMCP_FORM_ETC WHERE 1=1
AND CD_GROUP_ID1 = #{selectCdGroupId1}
AND CD_GROUP_ID2 = #{selectCdGroupId2}
ORDER BY CD_GROUP_ID2 ,DOC_VER

SELECT CD_GROUP_ID ,DTL_CD ,DTL_CD_NM FROM NMCP_CD_DTL WHERE 1=1 AND USE_YN = 'Y' AND CD_GROUP_ID IN ('FORMREQUIRED','FORMSELECT','FORMINFO')
AND CD_GROUP_ID = #{selectCdGroupId1}
ORDER BY CD_GROUP_ID,INDC_ODRG

SELECT CD_GROUP_ID ,DTL_CD ,DTL_CD_NM FROM NMCP_CD_DTL WHERE 1=1 AND USE_YN = 'Y' AND CD_GROUP_ID IN ('FormNotice','FormEtcCla')
AND CD_GROUP_ID = #{selectCdGroupId1}
ORDER BY CD_GROUP_ID,INDC_ODRG
